%simple echo generation
clear;
clc;

alpha = 0.8; %must be between 0 and 1 
N=7000; %delay

%read the audio signal
[x,t] = audioread('sounds.wav'); 

for n=1:length(x)
    if (n        y(n)=x(n);
    elseif (n>N) %echo generation
        y(n)=x(n)+(alpha*x(n-N));
    end
end
audiowrite('afterecho.wav',y,t); %after the echo added
soundsc(y,t);

echo = y(n);

%ploting input signal
plot(x);
title('input signal (without echo)');
xlabel('time');
ylabel('amplitude');

%ploting output signal
plot(y);
title('output signal (with echo)');
xlabel('time');
ylabel('amplitude');

% adding legend
figure;
plot(t,x);
hold on;
plot(t,y);
hold off;
title('input and output signal comparison');
xlabel('time');
ylabel('amplitude');
legend('input signal','output signal');

